    // WASM 状态更新函数
    window.updateWasmStatus = function(state) {
        var wasmDot = document.getElementById('wasmDot');
        var wasmStatus = document.getElementById('wasmStatus');
        if (!wasmDot || !wasmStatus) return;
        
        if (state === 'connecting') {
            wasmDot.className = 'status-dot yellow';
            wasmStatus.textContent = '视频: 连接中...';
        } else if (state === 'connected') {
            wasmDot.className = 'status-dot green';
            wasmStatus.textContent = '视频: WASM';
        } else if (state === 'disconnected') {
            wasmDot.className = 'status-dot red';
            wasmStatus.textContent = '视频: 未连接';
        }
    };
    
    // v6.18: 简化快速连接 - 直接从后端获取上次设备
