@api_router.post("/system/restart", summary="重启 AstroHub", tags=["System"])
async def restart_astrohub() -> dict:
    """重启 AstroHub 服务。"""
    import subprocess
    import sys
    import os

    try:
        # 创建重启脚本
        restart_cmd = f'sleep 2 && cd "{os.getcwd()}" && python -m uvicorn src.main.main:app --host 0.0.0.0 --port 10280'

        # 使用 subprocess 启动新进程
        subprocess.Popen(restart_cmd, shell=True, cwd=os.getcwd())

        # 延迟后退出当前进程
        import threading
        def delayed_exit():
            time.sleep(1)
            os._exit(0)
        threading.Thread(target=delayed_exit, daemon=True).start()

        return {"success": True, "message": "重启中..."}
    except Exception as e:
        return {"success": False, "message": f"重启失败: {e}"}

